ValidationRule.errorConditionFormula:
AND(
NOT(
OR(
ISBLANK(MobilePhone),
REGEX(MobilePhone, "^\\+44\\d{10}$"),
REGEX(MobilePhone, "^0\\d{10}$")
)
),
NOT(
OR(
$Profile.Name = "Minimum Access - API Only Integrations",
$Profile.Name = "System Administrator",
$Profile.Name = "B2BMA Integration User"
)
)
)
